mapper.select:
SELECT s.schedule_id, s.doctor_id, d.name AS doctor_name, s.dept_id, dept.name AS dept_name, s.schedule_date, s.time_slot, s.total_slots, s.booked_slots, (s.total_slots - s.booked_slots) AS remaining_slots, s.status, CASE WHEN s.status = 1 THEN '可预约' ELSE '停诊' END AS status_text, s.created_time FROM schedule s LEFT JOIN doctor d ON s.doctor_id = d.doctor_id LEFT JOIN sys_dept dept ON s.dept_id = dept.dept_id
AND s.dept_id = #{param.deptId}
AND s.doctor_id = #{param.doctorId}
AND s.status = #{param.status}
AND s.schedule_date >= #{param.startDate}
AND s.schedule_date <= #{param.endDate}
ORDER BY s.schedule_date DESC, s.created_time DESC

SELECT COUNT(*)
FROM schedule
WHERE doctor_id = #{doctorId}
AND schedule_date = #{scheduleDate}
AND time_slot = #{timeSlot}

    AND schedule_id != #{excludeId}
